<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: system-ui, -apple-system, sans-serif; background: #f4f6f8; color: #222; line-height: 1.5; padding: 1rem; max-width: 720px; margin: 0 auto; }
  h1 { font-size: 1.4rem; margin-bottom: 1rem; }
  h2 { font-size: 1.1rem; margin: 1.5rem 0 0.6rem; }

  /* Form */
  .entry-form { background: #fff; padding: 1rem; border-radius: 8px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 1rem; }
  .form-row { display: flex; gap: .5rem; flex-wrap: wrap; align-items: flex-end; }
  .form-group { display: flex; flex-direction: column; gap: .2rem; }
  .form-group label { font-size: .8rem; font-weight: 600; color: #444; }
  input, select { padding: .45rem .5rem; border: 1px solid #ccc; border-radius: 4px; font-size: .9rem; }
  input:focus, select:focus { outline: none; border-color: #3b82f6; box-shadow: 0 0 0 2px rgba(59,130,246,.2); }
  #amount { width: 110px; }
  #category { width: 130px; }
  #date { width: 150px; }
  #note { flex: 1; min-width: 120px; }
  #add-expense { padding: .45rem 1.2rem; background: #2563eb; color: #fff; border: none; border-radius: 4px; cursor: pointer; font-size: .9rem; font-weight: 600; align-self: flex-end; }
  #add-expense:hover { background: #1d4ed8; }

  /* Error */
  #form-error { color: #dc2626; font-size: .85rem; min-height: 1.3em; margin-top: .5rem; }

  /* Filters */
  .filters-bar { background: #fff; padding: .75rem 1rem; border-radius: 8px; box-shadow: 0 1px 3px rgba(0,0,0,.1); display: flex; gap: .5rem; align-items: center; flex-wrap: wrap; margin-bottom: 1rem; }
  .filters-bar label { font-size: .8rem; font-weight: 600; color: #444; }
  .filter-group { display: flex; align-items: center; gap: .25rem; }

  /* Summary */
  .summary-bar { background: #fff; padding: .75rem 1rem; border-radius: 8px; box-shadow: 0 1px 3px rgba(0,0,0,.1); display: flex; gap: 2rem; align-items: center; flex-wrap: wrap; margin-bottom: 1rem; }
  .summary-bar strong { font-size: 1.1rem; }
  #total { color: #16a34a; font-weight: 700; }
  .cat-total { display: inline-block; padding: .2rem .5rem; border-radius: 4px; background: #f0fdf4; font-size: .85rem; margin-right: .3rem; }

  /* Expense list */
  .expense-list { list-style: none; }
  .expense { display: flex; justify-content: space-between; align-items: center; padding: .6rem 1rem; background: #fff; border-bottom: 1px solid #e5e7eb; gap: .5rem; }
  .expense:first-child { border-radius: 8px 8px 0 0; }
  .expense:last-child { border-radius: 0 0 8px 8px; border-bottom: none; }
  .expense:only-child { border-radius: 8px; }
  .exp-info { flex: 1; min-width: 0; }
  .exp-amount { font-weight: 700; color: #dc2626; white-space: nowrap; }
  .exp-cat { display: inline-block; background: #eff3ff; color: #3b82f6; padding: .1rem .45rem; border-radius: 3px; font-size: .75rem; text-transform: capitalize; margin-left: .4rem; }
  .exp-date { font-size: .8rem; color: #6b7280; }
  .exp-note { font-size: .8rem; color: #9ca3af; font-style: italic; max-width: 150px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
  .exp-del { background: none; border: 1px solid #fca5a5; color: #dc2626; padding: .2rem .6rem; border-radius: 4px; cursor: pointer; font-size: .8rem; }
  .exp-del:hover { background: #fef2f2; }

  /* Empty state */
  .empty-msg { text-align: center; color: #9ca3af; padding: 2rem; font-style: italic; }

  @media (max-width: 500px) {
    .form-row { flex-direction: column; align-items: stretch; }
    #amount, #category, #date { width: 100%; }
    .summary-bar { flex-direction: column; gap: .5rem; align-items: flex-start; }
  }
</style>
</head>
<body>

<h1>💰 Expense Tracker</h1>

<!-- Entry Form -->
<div class="entry-form">
  <div class="form-row">
    <div class="form-group">
      <label for="amount">Amount ($)</label>
      <input type="number" id="amount" placeholder="0.00" step="0.01" min="0">
    </div>
    <div class="form-group">
      <label for="category">Category</label>
      <select id="category">
        <option value="">— select —</option>
        <option value="groceries">groceries</option>
        <option value="transport">transport</option>
        <option value="bills">bills</option>
        <option value="fun">fun</option>
      </select>
    </div>
    <div class="form-group">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="form-group">
      <label for="note">Note (optional)</label>
      <input type="text" id="note" placeholder="e.g. weekly shop">
    </div>
    <button id="add-expense">Add Expense</button>
  </div>
  <div id="form-error"></div>
</div>

<!-- Filters -->
<div class="filters-bar">
  <span style="font-weight:700;font-size:.85rem;">Filters:</span>
  <div class="filter-group">
    <label for="filter-category">Cat:</label>
    <select id="filter-category">
      <option value="all">all</option>
      <option value="groceries">groceries</option>
      <option value="transport">transport</option>
      <option value="bills">bills</option>
      <option value="fun">fun</option>
    </select>
  </div>
  <div class="filter-group">
    <label for="filter-from">From:</label>
    <input type="date" id="filter-from">
  </div>
  <div class="filter-group">
    <label for="filter-to">To:</label>
    <input type="date" id="filter-to">
  </div>
</div>

<!-- Summary -->
<div class="summary-bar">
  <span>Total: <strong><span id="total">0.00</span></strong></span>
  <span>By category:</span>
  <span class="cat-total" data-cat="groceries">groceries: <strong>0.00</strong></span>
  <span class="cat-total" data-cat="transport">transport: <strong>0.00</strong></span>
  <span class="cat-total" data-cat="bills">bills: <strong>0.00</strong></span>
  <span class="cat-total" data-cat="fun">fun: <strong>0.00</strong></span>
</div>

<!-- Expense List -->
<ul id="expense-list" class="expense-list"></ul>

<script>
(function() {
  const STORAGE_KEY = 'expense_tracker_data';
  const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  // DOM refs
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const addBtn = document.getElementById('add-expense');
  const formError = document.getElementById('form-error');
  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');
  const totalEl = document.getElementById('total');
  const expenseList = document.getElementById('expense-list');

  // State
  let expenses = loadExpenses();

  function loadExpenses() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? JSON.parse(raw) : [];
    } catch { return []; }
  }

  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // Set default date to today
  dateInput.value = new Date().toISOString().slice(0, 10);

  // Add expense handler
  addBtn.addEventListener('click', () => {
    const amountVal = amountInput.value.trim();
    const catVal = categorySelect.value;
    const dateVal = dateInput.value.trim();
    const noteVal = noteInput.value.trim();

    formError.textContent = '';

    // Validate amount: must be present, numeric, positive
    if (!amountVal || isNaN(amountVal) || Number(amountVal) <= 0) {
      formError.textContent = 'Please enter a valid positive amount.';
      return;
    }

    // Validate date: must not be empty
    if (!dateVal) {
      formError.textContent = 'Please select a date.';
      return;
    }

    const expense = {
      id: Date.now().toString(36) + Math.random().toString(36).slice(2, 7),
      amount: parseFloat(Number(amountVal).toFixed(2)),
      category: catVal || 'groceries',
      date: dateVal,
      note: noteVal,
      createdAt: Date.now()
    };

    expenses.unshift(expense); // newest first
    saveExpenses();
    render();

    // Reset amount field only (as specified)
    amountInput.value = '';
  });

  // Delete handler (delegated)
  expenseList.addEventListener('click', (e) => {
    if (e.target.classList.contains('exp-del')) {
      const id = e.target.dataset.id;
      expenses = expenses.filter(exp => exp.id !== id);
      saveExpenses();
      render();
    }
  });

  // Filter handlers
  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('input', render);
  filterTo.addEventListener('input', render);

  function getVisibleExpenses() {
    const catFilter = filterCategory.value;
    const fromVal = filterFrom.value;
    const toVal = filterTo.value;

    return expenses.filter(exp => {
      if (catFilter !== 'all' && exp.category !== catFilter) return false;
      if (fromVal && exp.date < fromVal) return false;
      if (toVal && exp.date > toVal) return false;
      return true;
    });
  }

  function formatCurrency(n) {
    return n.toFixed(2);
  }

  function render() {
    const visible = getVisibleExpenses();

    // Render list
    if (visible.length === 0) {
      expenseList.innerHTML = '<li class="empty-msg">No expenses to show.</li>';
    } else {
      expenseList.innerHTML = visible.map(exp => `
        <li class="expense" data-id="${exp.id}">
          <div class="exp-info">
            <span class="exp-amount">$${formatCurrency(exp.amount)}</span>
            <span class="exp-cat">${exp.category}</span>
            <div class="exp-date">${exp.date}${exp.note ? ' — ' + escapeHtml(exp.note) : ''}</div>
          </div>
          <button class="exp-del" data-id="${exp.id}">✕</button>
        </li>
      `).join('');
    }

    // Compute totals
    const total = visible.reduce((sum, exp) => sum + exp.amount, 0);
    totalEl.textContent = formatCurrency(total);

    // Per-category totals (visible only)
    CATEGORIES.forEach(cat => {
      const catTotal = visible.filter(exp => exp.category === cat).reduce((s, e) => s + e.amount, 0);
      const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
      if (el) {
        el.innerHTML = `${cat}: <strong>${formatCurrency(catTotal)}</strong>`;
      }
    });
  }

  function escapeHtml(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  // Initial render
  render();
})();
</script>
</body>
</html>
